def restore_ip(s: str):
    res = []
    def valid(seg: str) -> bool:
        if len(seg) == 0 or len(seg) > 3:
            return False
        if seg[0] == '0' and len(seg) > 1:
            return False
        return int(seg) <= 255
    def dfs(i, parts, path):
        if parts == 4 and i == len(s):
            res.append(path[:-1])
            return
        if parts == 4 or i == len(s):
            return
        for l in range(1, 4):
            if i + l <= len(s) and valid(s[i:i+l]):
                dfs(i + l, parts + 1, path + s[i:i+l] + ".")
    dfs(0, 0, "")
    return res

